// Complete I Ching 64 Hexagram Reference
// Each hexagram: number, name (Chinese + English), trigrams, judgment, image, meaning

export interface HexagramLine {
  type: 'yang' | 'yin';       // solid or broken
  changing: boolean;           // old yang (9) or old yin (6)
}

export interface Trigram {
  name: string;
  chinese: string;
  attribute: string;
  image: string;
  lines: [boolean, boolean, boolean]; // bottom to top, true = yang
}

export const TRIGRAMS: Record<string, Trigram> = {
  '111': { name: 'Qian', chinese: '乾', attribute: 'Creative', image: 'Heaven', lines: [true, true, true] },
  '000': { name: 'Kun', chinese: '坤', attribute: 'Receptive', image: 'Earth', lines: [false, false, false] },
  '100': { name: 'Zhen', chinese: '震', attribute: 'Arousing', image: 'Thunder', lines: [true, false, false] },
  '010': { name: 'Kan', chinese: '坎', attribute: 'Abysmal', image: 'Water', lines: [false, true, false] },
  '001': { name: 'Gen', chinese: '艮', attribute: 'Keeping Still', image: 'Mountain', lines: [false, false, true] },
  '011': { name: 'Xun', chinese: '巽', attribute: 'Gentle', image: 'Wind/Wood', lines: [false, true, true] },
  '101': { name: 'Li', chinese: '離', attribute: 'Clinging', image: 'Fire', lines: [true, false, true] },
  '110': { name: 'Dui', chinese: '兌', attribute: 'Joyous', image: 'Lake', lines: [true, true, false] },
};

export interface Hexagram {
  number: number;
  name: string;
  chinese: string;
  pinyin: string;
  upperTrigram: string; // key into TRIGRAMS
  lowerTrigram: string;
  judgment: string;
  image: string;
  meaning: string;
  keywords: string[];
  changingLines: Record<number, string>; // 1-6 from bottom
}

// King Wen lookup is used instead of flat map (avoids duplicate key issues)

// Better approach: Use King Wen sequence lookup table
// Index by [upper trigram index][lower trigram index]
// Trigram order: Qian(111), Kun(000), Zhen(100), Kan(010), Gen(001), Xun(011), Li(101), Dui(110)
const T_ORDER = ['111', '000', '100', '010', '001', '011', '101', '110'];

// King Wen sequence: KING_WEN[upper][lower] = hexagram number
export const KING_WEN: number[][] = [
  // Upper\Lower: Qian  Kun  Zhen Kan  Gen  Xun  Li   Dui
  /* Qian  111 */ [1,   12,  25,  6,   33,  44,  13,  10],
  /* Kun   000 */ [11,  2,   24,  7,   15,  46,  36,  19],
  /* Zhen  100 */ [34,  16,  51,  3,   62,  32,  55,  54],
  /* Kan   010 */ [5,   8,   40,  29,  39,  48,  63,  60],
  /* Gen   001 */ [26,  23,  27,  4,   52,  18,  22,  41],
  /* Xun   011 */ [9,   20,  42,  59,  53,  57,  37,  61],
  /* Li    101 */ [14,  35,  21,  64,  56,  50,  30,  38],
  /* Dui   110 */ [43,  45,  17,  47,  31,  28,  49,  58],
];

export function lookupHexagramNumber(upperKey: string, lowerKey: string): number {
  const ui = T_ORDER.indexOf(upperKey);
  const li = T_ORDER.indexOf(lowerKey);
  if (ui === -1 || li === -1) return 1;
  return KING_WEN[ui][li];
}

