// Get hexagram by number
export function getHexagram(num: number): Hexagram | undefined {
  return HEXAGRAMS.find(h => h.number === num);
}

// Convert 6 lines to hexagram
export function linesToHexagram(lines: HexagramLine[]): { primary: Hexagram; transformed: Hexagram | null } {
  // Lines are bottom (0) to top (5)
  const lowerBits = lines.slice(0, 3).map(l => l.type === 'yang' ? '1' : '0').join('');
  const upperBits = lines.slice(3, 6).map(l => l.type === 'yang' ? '1' : '0').join('');
  
  const primaryNum = lookupHexagramNumber(upperBits, lowerBits);
  const primary = getHexagram(primaryNum)!;
  
  // Check for changing lines
  const hasChanging = lines.some(l => l.changing);
  let transformed: Hexagram | null = null;
  
  if (hasChanging) {
    const transformedLines = lines.map(l => ({
      ...l,
      type: l.changing ? (l.type === 'yang' ? 'yin' : 'yang') as 'yang' | 'yin' : l.type,
      changing: false,
    }));
    const tLowerBits = transformedLines.slice(0, 3).map(l => l.type === 'yang' ? '1' : '0').join('');
    const tUpperBits = transformedLines.slice(3, 6).map(l => l.type === 'yang' ? '1' : '0').join('');
    const tNum = lookupHexagramNumber(tUpperBits, tLowerBits);
    transformed = getHexagram(tNum)!;
  }
  
  return { primary, transformed };
}

// Three-coin method: each coin is 2 (tails) or 3 (heads)
// Sum of 3 coins: 6=old yin, 7=young yang, 8=young yin, 9=old yang
export function throwCoins(): { sum: number; line: HexagramLine } {
  const coins = [
    Math.random() < 0.5 ? 2 : 3,
    Math.random() < 0.5 ? 2 : 3,
    Math.random() < 0.5 ? 2 : 3,
  ];
  const sum = coins[0] + coins[1] + coins[2];
  return {
    sum,
    line: sumToLine(sum),
  };
}

export function sumToLine(sum: number): HexagramLine {
  switch (sum) {
    case 6: return { type: 'yin', changing: true };   // Old Yin ⚋✕
    case 7: return { type: 'yang', changing: false };  // Young Yang ⚊
    case 8: return { type: 'yin', changing: false };   // Young Yin ⚋
    case 9: return { type: 'yang', changing: true };   // Old Yang ⚊✕
    default: return { type: 'yang', changing: false };
  }
}

// Manual penny values: H=3, T=2
export function pennyResult(coin1: 'H' | 'T', coin2: 'H' | 'T', coin3: 'H' | 'T'): { sum: number; line: HexagramLine } {
  const val = (c: 'H' | 'T') => c === 'H' ? 3 : 2;
  const sum = val(coin1) + val(coin2) + val(coin3);
  return { sum, line: sumToLine(sum) };
}
